const axios = require('axios').default;

axios.defaults.headers['Content-Type'] = 'application/json;charset=utf-8';

const zhiyaService = axios.create({
    // axios 请求中 URL 的公共部分
    baseURL: '/zhiya',
    // 设置请求超时时间
    timeout: 10 * 1000
})

// 请求拦截器
zhiyaService.interceptors.request.use(config => {
    let token = localStorage.getItem('zhiya_token') ? 'Bearer ' + localStorage.getItem('zhiya_token') : ''
    config.headers.Authorization = token
    return config
})

// 响应拦截器
zhiyaService.interceptors.response.use(res => {
    return res.data
}, error => {
    window.globalMsg.tips = {
        visible: true,
        content: error.message,
        type: 'fail',
        data: new Date()
    }
    return Promise.reject(error);
})

module.exports = zhiyaService;