/* canvas画板 */
class Drawer {
    constructor(id, config) {
        let { log } = console
        this.canvas = document.getElementById(id)
        this.ctx = null
        this.operation = null // 操作 0绘制 1拖拽 2伸缩
        this.is_draw = false // 是否处于绘制
        this.flag = false // 点击鼠标

        this.must = 'color' // 必须条件，符合开启功能

        this.text = config?.text || {}
        
        // 功能配置
        this.color = null // 颜色
        this.label_name = '' // 颜色标签名称
        this.transparent_color = null // 透明颜色
        this.img = null // 图像
        // 撤销/重做
        this.undo_list = [] // 用于保存所有操作，用于撤销和重做
        this.redo_list = [] // 用于保存所有撤销的操作，用于重做
        this.id = 0

        this.layers = [] // 图层
        this.position = { // 坐标(当前操作的坐标)
            x1: 0,
            y1: 0,
            x2: 0,
            y2: 0
        }
        // 拖拽
        this.drag_index = null // 拖拽下标
        this.pre_drag_index = null // 上一次拖拽
        this.drag_position = { // 拖拽坐标
            x: 0,
            y: 0
        }
        // 伸缩
        this.is_scale = config?.scale || false // 控制伸缩功能
        this.scale_index = null // 伸缩下标
        this.scale_position = { // 保存颠倒的坐标
            x1: null,
            y1: null,
            x2: null,
            y2: null
        }
        this.reverse = false // 坐标是否颠倒
        this.auxiliary_line = false // 伸缩辅助线
        this.scale_color = 'black'
        // 旋转
        this.is_rotate = config?.rotate || false // 旋转功能
        this.rotate_angle = 0 // 旋转角度
        this.rotate_img = null // 旋转图标
        this.rotate_img_src = config?.rotate_img_src || '' // 旋转图片路径

        // 事件传递参数
        this.event = {
            type: null,
            id: null
        }

        this.initRotateImg()

        this.canvas.onmousedown = this.onmousedown
        this.canvas.onmousemove = this.onmousemove
        this.canvas.onmouseup = this.onmouseup
        this.canvas.onclick = this.onclick
        
        // 判断浏览器是否支持
        if (this.canvas.getContext) {
            this.ctx = this.canvas.getContext('2d')
        } else {
            throw new Error('浏览器不支持')
        }
    }
    initRotateImg = () => {
        if (this.rotate_img === null) {
            this.rotate_img = new Image()
            this.rotate_img.src = this.rotate_img_src
        }
    }
    // 获取撤销
    getUndo = () => {
        return this.undo_list.length
    }
    // 获取重做
    getRedo = () => {
        return this.redo_list.length
    }
    // 撤销
    undoHandle = () => {
        if (this.undo_list.length === 0) return false
        // 关闭辅助线
        this.pre_drag_index = null 
        this.auxiliary_line = false

        let cur = this.undo_list.pop()
        let arr = this.undo_list.filter((item) => item.id === cur.id)
        if (arr.length > 0) {
            let prev = this.undo_list[this._undo_list.length - 1]
            if (cur.id === prev.id) {
                let index = this.layers.findIndex((item) => item.id === prev.id)
                this.layers[index] = {...prev}
            } else {
                let index = this.layers.findIndex((item) => item.id === cur.id)
                this.layers[index] = {...arr[arr.length -1]}
            }
        } else {
            this.layers.pop()
        }
        this.redo_list.push(cur)
        this.drawAll()
    }
    // 重做
    redoHandle = () => {
        if (this.redo_list.length === 0) return
        let cur = this.redo_list.pop()
        let index = this.layers.findIndex((item) => item.id === cur.id)
        if (this.layers.length === 0 || index === -1) {
            this.layers.push({...cur})
        } else {
            this.layers[index] = {...cur}
        }

        this.undo_list.push(cur)
        this.drawAll()
    }
    // 删除
    removeSelectRect = () => {
        if (this.auxiliary_line) {
            this.layers.splice(this.drag_index, 1)
            this.drag_index = null
            this.auxiliary_line = false
            this.drawAll()
        }
    }
    clearAll = () => {
        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height)
    }
    // 设置鼠标样式
    setCursor = (pos) => {
        let index = this.#isInCornerPath(pos.x, pos.y, this.layers[this.drag_index])
        if (index != null) {
            if (this.layers[this.drag_index].x1 < this.layers[this.drag_index].x2 && this.layers[this.drag_index].y1 < this.layers[this.drag_index].y2) {
                this.canvas.style.cursor = 'se-resize'
            } else if (this.layers[this.drag_index].x1 < this.layers[this.drag_index].x2 && this.layers[this.drag_index].y1 > this.layers[this.drag_index].y2) {
                this.canvas.style.cursor = 'ne-resize'
            } else if (this.layers[this.drag_index].x1 > this.layers[this.drag_index].x2 && this.layers[this.drag_index].y1 < this.layers[this.drag_index].y2) {
                this.canvas.style.cursor = 'sw-resize'
            } else if (this.layers[this.drag_index].x1 > this.layers[this.drag_index].x2 && this.layers[this.drag_index].y1 > this.layers[this.drag_index].y2) {
                this.canvas.style.cursor = 'nw-resize'
            }
        } else {
            this.canvas.style.cursor = ''
        }
        // if (index === 0) {
        //     this.canvas.style.cursor = 'nw-resize'
        // } else if (index === 1) {
        //     this.canvas.style.cursor = 'ne-resize'
        // } else if (index === 2) {
        //     this.canvas.style.cursor = 'sw-resize'
        // } else if (index === 3) {
        //     if (this.reverse) {
                
        //     } else {
        //         this.canvas.style.cursor = 'se-resize'
        //     }
        // } else {
        //     this.canvas.style.cursor = ''
        // }
    }
    // 设置伸缩功能
    setScale = (type) => {
        this.is_scale = type
    }
    // 设置旋转功能
    setRotate = (type) => {
        this.is_rotate = type
    }
    // 设置颜色
    setColor = (type) => {
        if (type === this.color) {
            this.color = null
        } else {
            this.color = type
        }
    }
    // 设置标签名称
    setLabelName = (type) => {
        this.label_name = type
    }
    // 设置背景图
    setBackgroundImage = (image) => {
        this.img = new Image()
        this.img.src = image
        this.img.onload = (e) => {
            // this.drawImage()
            this.drawAll()
        }
    }
    // 绘制图片
    drawImage = () => {
        if (this.img) {
            this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height)
            this.ctx.drawImage(this.img, 0, 0, this.canvas.width, this.canvas.height)
        }
    }
    // 绘制透明矩形
    drawTransparentRect = (x1, y1, x2, y2, w = 4, h = 8) => {
        this.ctx.beginPath()
        this.ctx.fillStyle = 'rgba(255, 255, 255, 0.5)'
        if (x1 > x2 && y1 > y2) {
            this.ctx.fillRect(x1 - w, y1 - w, x2 - x1 + h, y2 - y1 + h)
        } else if (x1 < x2 && y1 < y2) {
            this.ctx.fillRect(x1 + w, y1 + w, x2 - x1 - h, y2 - y1 - h)
        } else if (x1 < x2 && y1 > y2) {
            this.ctx.fillRect(x1 + w, y1 - w, x2 - x1 - h, y2 - y1 + h)
        } else if (x1 > x2 && y1 < y2) {
            this.ctx.fillRect(x1 - w, y1 + w, x2 - x1 + h, y2 - y1 - h)
        }
        this.ctx.closePath()
    }
    // 绘制矩形
    drawRect = () => {
        this.drawAll()
        let {x1, y1, x2, y2} = this.position
        this.ctx.beginPath()
        this.ctx.moveTo(x1, y1)
        this.ctx.fillStyle = this.color
        this.ctx.fillRect(x1, y1, x2 - x1, y2 - y1)
        this.ctx.closePath()

        // 画内边距透明矩形
        this.drawTransparentRect(x1, y1, x2, y2)
        this.is_draw = true
    }
    // 绘制文本
    drawText = (text, x1, y1, size) => {
        this.ctx.beginPath()
        this.ctx.fillStyle = 'red'
        this.ctx.font = `${12}px serif`
        this.ctx.fillText(
            text,
            x1,
            y1
        )
        this.ctx.closePath()
    }
    // 重新绘制图形
    drawAll = () => {
        this.ctx.clearRect(-this.canvas.width, -this.canvas.height, this.canvas.width * 2, this.canvas.height * 2)
        // this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height)
        if (this.img) this.drawImage()
        this.layers.forEach((item, index) => {
            if (this.is_rotate && item.rotate && item.rotate != null) {
                this.ctx.translate(item.center_point.x, item.center_point.y)
                this.ctx.rotate(item.rotate * Math.PI / 180)

                this.ctx.beginPath()
                this.ctx.fillStyle = 'red'
                this.ctx.strokeStyle = this.scale_color
                this.ctx.fillRect(
                    -20 /2,
                    -20 /2,
                    20,
                    20
                )
                this.ctx.closePath()

                this.ctx.beginPath()
                this.ctx.fillStyle = item.color
                this.ctx.strokeStyle = this.scale_color
                this.ctx.fillRect(
                    0,
                    0,
                    item.x2 - item.x1,
                    item.y2 - item.y1
                )
                this.ctx.closePath()

                // 绘制内边距透明矩形
                this.ctx.beginPath()
                this.ctx.fillStyle = 'rgba(255, 255, 255, 0.5)'
                if (item.x1 > item.x2 && item.y1 > item.y2) {
                    this.ctx.fillRect(
                        -(item.x2 - item.x1)/2 - 5, 
						-(item.y2 - item.y1)/2 - 5, 
						item.x2 - item.x1 + 10, 
						item.y2 - item.y1 + 10
                    )
                } else if (item.x1 < item.x2 && item.y1 < item.y2) {
                    this.ctx.fillRect(
						-(item.x2 - item.x1)/2 + 5, 
						-(item.y2 - item.y1)/2 + 5, 
						item.x2 - item.x1 - 10, 
						item.y2 - item.y1 - 10
					)
                } else if (item.x1 < item.x2 && item.y1 > item.y2) {
                    this.ctx.fillRect(
						-(item.x2 - item.x1)/2 + 5, 
						-(item.y2 - item.y1)/2 - 5, 
						item.x2 - item.x1 - 10, 
						item.y2 - item.y1 + 10
					)
                } else if (item.x1 > item.x2 && item.y1 < item.y2) {
                    this.ctx.fillRect(
						-(item.x2 - item.x1)/2 - 5, 
						-(item.y2 - item.y1)/2 + 5, 
						item.x2 - item.x1 + 10, 
						item.y2 - item.y1 -10
					)
                }
                this.ctx.closePath()

                if (this.drag_index === 0 || this.drag_index) {
                    // 绘制辅助线
                    if (this.auxiliary_line && index === this.drag_index) {
                        // 伸缩
                        if (this.is_scale) {
                            let arr = [
                                {
                                    x: -(item.x2 - item.x1)/2 - 5,
                                    y: -(item.y2 - item.y1)/2 + 5,
                                },
                                {
                                    x: (item.x2 - item.x1)/2 - 5,
                                    y: -(item.y2 - item.y1)/2 + 5,
                                },
                                {
                                    x: -(item.x2 - item.x1)/2 - 5,
                                    y: (item.y2 - item.y1)/2 + 5,
                                },
                                {
                                    x: (item.x2 - item.x1)/2 - 5,
                                    y: (item.y2 - item.y1)/2 + 5,
                                }
                            ]
                            
                            this.layers[this.drag_index].coordinate.forEach((v, i) => {
                                // this.ctx.beginPath()
                                // this.ctx.strokeStyle = this.scale_color
                                // this.ctx.strokeRect(
                                //     arr[i].x,
                                //     arr[i].y,
                                //     v.x2 - v.x1, 
                                //     v.y2 - v.y1
                                // )
                                // this.ctx.closePath()
                                this.ctx.beginPath()
                                this.ctx.fillStyle = '#09f'
                                this.ctx.fillRect(
                                    arr[i].x,
                                    arr[i].y,
                                    v.x2 - v.x1, 
                                    v.y2 - v.y1
                                )
                                // this.ctx.strokeStyle = '#09f'
                                // this.ctx.strokeRect(v.x1, v.y1, v.x2 - v.x1, v.y2 - v.y1)
                                this.ctx.closePath()
                            })
                        }

                        // 旋转
                        if (this.is_rotate && this.layers[this.drag_index].rotate_coordinate) {
                            if (this.rotate_img === null) {
                                this.rotate_img = new Image()
                                this.rotate_img.src = this.rotate_img_src
                                this.rotate_img.onload = (e) => {
                                    this.ctx.beginPath()
                                    let minImg = Math.min(item.y2, item.y1)
                                    let maxImg = Math.max(item.y2, item.y1)

                                    this.ctx.drawImage(
                                        this.rotate_img, 
                                        this.rotate_img.width / 2,
                                        this.rotate_img.height / 2 + (maxImg - minImg)/2  + 10,
                                        this.rotate_img.width, 
                                        this.rotate_img.height
                                    )
                                }
                            } else {
                                this.ctx.beginPath()
                                let minImg = Math.min(item.y2, item.y1)
                                let maxImg = Math.max(item.y2, item.y1)
                                this.ctx.drawImage(
                                    this.rotate_img, 
                                    0 - this.rotate_img.height / 2,
                                    0 - this.rotate_img.height / 2 + (maxImg - minImg)/2 + 10,
                                    this.rotate_img.width, 
                                    this.rotate_img.height
                                )
                            }
                        }
                    }


                    // 设置旋转后的坐标
                    this.layers[this.drag_index].rotate_after_coordinate = this.calculateRotatedRectCoordinates()

                    // 设置旋转后的旋转图标的坐标
                    this.layers[this.drag_index].rotate_img_coordinate = this.calculateRotatedImgCoordinates()
                }

                this.ctx.rotate(-item.rotate * Math.PI / 180)
                this.ctx.translate(-item.center_point.x, -item.center_point.y)
            } else {
                this.ctx.beginPath()
                this.ctx.fillStyle = item.color
                this.ctx.fillRect(item.x1, item.y1, item.x2 - item.x1, item.y2 - item.y1)
                this.ctx.closePath()

                // 绘制内边距透明矩形
                this.drawTransparentRect(item.x1, item.y1, item.x2, item.y2)
                // 绘制辅助线
                if (this.drag_index === 0 || this.drag_index) {
                    if (this.auxiliary_line && index === this.drag_index) {
                        // 伸缩
                        if (this.is_scale) {
                            this.layers[this.drag_index].coordinate.forEach((v, i) => {
                                this.ctx.beginPath()
                                this.ctx.fillStyle = '#09f'
                                this.ctx.fillRect(v.x1, v.y1, v.x2 - v.x1, v.y2 - v.y1)
                                // this.ctx.strokeStyle = '#09f'
                                // this.ctx.strokeRect(v.x1, v.y1, v.x2 - v.x1, v.y2 - v.y1)
                                this.ctx.closePath()
                            })
                        }

                        // 旋转
                        if (this.is_rotate && this.layers[this.drag_index].rotate_coordinate) {
                            if (this.rotate_img === null) {
                                this.rotate_img = new Image()
                                this.rotate_img.src = this.rotate_img_src
                                this.rotate_img.onload = (e) => {
                                    this.ctx.beginPath()
                                    this.ctx.drawImage(
                                        this.rotate_img,
                                        this.layers[this.drag_index].rotate_coordinate.x - this.rotate_img.width / 2, 
                                        this.layers[this.drag_index].rotate_coordinate.y - this.rotate_img.height / 2 - 10, 
                                        this.rotate_img.width, 
                                        this.rotate_img.height
                                    )
                                }
                            } else {
                                this.ctx.beginPath()
                                this.ctx.drawImage(
                                    this.rotate_img, 
                                    this.layers[this.drag_index].rotate_coordinate.x - this.rotate_img.width / 2, 
                                    this.layers[this.drag_index].rotate_coordinate.y - this.rotate_img.height / 2 - 10, 
                                    this.rotate_img.width, 
                                    this.rotate_img.height
                                )
                            }
                        }

                        // 文本
                        let width = Math.abs(this.layers[this.drag_index].x2 - this.layers[this.drag_index].x1)
                        let heigth = Math.abs(this.layers[this.drag_index].y2 - this.layers[this.drag_index].y1)
                        this.drawText(
                            this.text?.delete || '删除',
                            this.layers[this.drag_index].remove_coordinate.x1,
                            this.layers[this.drag_index].remove_coordinate.y1,
                            width/heigth,
                        )
                    }
                }
            }
        })
    }
    // 获取图层数据
    getLayers = () => {
        return this.layers
    }
    // 重置默认值
    resizeDefault = () => {
        this.flag = false
        this.is_draw = false
        this.operation = null
        this.reverse = null
        this.position = {
            x1: 0,
            y1: 0,
            x2: 0,
            y2: 0
        }
        this.scale_position = {
            x1: null,
            y1: null
        }
        this.canvas.style.cursor = ''
    }
    // 重置配置
    resetConfig = () => {
        this.operation = null
        this.color = null
        this.layers = []
        
        this.is_draw = false
        this.flag = false
        this.auxiliary_line = false // 关闭辅助线
        this.drag_index = null
        this.pre_drag_index = null
    }
    // 获取坐标位置
    #getPosition = (e) => {
        let rect = this.canvas.getBoundingClientRect() // 返回元素的大小及其相对于视口的位置
        let x = (e.clientX - rect.left) * this.canvas.width / rect.width
        let y = (e.clientY - rect.top) * this.canvas.height / rect.height
        return {x, y}
    }
    // 获取四个顶点坐标
    #getCoordinate = (x1, y1, x2, y2, cornerWidth = 4) => {
        let leftTopPos = {
            x1: x1 - cornerWidth,
            y1: y1 + cornerWidth,
            x2: x1 + cornerWidth,
            y2: y1 - cornerWidth
        }
        let rightTopPos = {
            x1: x2 - cornerWidth,
            y1: y1 + cornerWidth,
            x2: x2 + cornerWidth,
            y2: y1 - cornerWidth,
        }
        let leftBottomPos = {
            x1: x1 - cornerWidth,
            y1: y2 + cornerWidth,
            x2: x1 + cornerWidth,
            y2: y2 - cornerWidth
        }
        let rightBottomPos = {
            x1: x2 - cornerWidth,
            y1: y2 + cornerWidth,
            x2: x2 + cornerWidth,
            y2: y2 - cornerWidth
        }

        return [leftTopPos, rightTopPos, leftBottomPos, rightBottomPos]
    }
    // 鼠标是否落在矩形图层上
    #isPointInRect = (x, y) => {
        // 从后面搜索，依据最后画的图层优先级高
        for (let i = this.layers.length - 1; i >= 0; i--) {
            let data = this.layers[i]
            // 处理不同方向绘制图形
            let minX = Math.min(data.x1, data.x2)
            let maxX = Math.max(data.x1, data.x2)
            let minY = Math.min(data.y1, data.y2)
            let maxY = Math.max(data.y1, data.y2)

            if (x >= minX && x <= maxX && y >= minY && y<= maxY) {
                return {
                    i,
                    ...data
                }
            }
        }
        return null
    }
    // 鼠标是否落在辅助框（区分旋转与非旋转）
    #isInCornerPath = (x, y, data) => {
        if (
            this.is_rotate && 
            data.rotate != null && 
            data.rotate_after_coordinate != null
        ) { // 旋转
            for (let i in data.rotate_after_coordinate) {
                let cornerWidth = 4
                let minX = Math.min(data.rotate_after_coordinate[i].x - cornerWidth, data.rotate_after_coordinate[i].x + cornerWidth)
                let maxX = Math.max(data.rotate_after_coordinate[i].x - cornerWidth, data.rotate_after_coordinate[i].x + cornerWidth)
                let minY = Math.min(data.rotate_after_coordinate[i].y + cornerWidth, data.rotate_after_coordinate[i].y - cornerWidth)
                let maxY = Math.max(data.rotate_after_coordinate[i].y + cornerWidth, data.rotate_after_coordinate[i].y - cornerWidth)
                
                if (x >= minX && x <= maxX && y >= minY && y<= maxY) {
                    return i
                }
            }
        } else {
            for (let i = 0; i < data.coordinate.length; i++) {
                let minX = Math.min(data.coordinate[i].x1, data.coordinate[i].x2)
                let maxX = Math.max(data.coordinate[i].x1, data.coordinate[i].x2)
                let minY = Math.min(data.coordinate[i].y1, data.coordinate[i].y2)
                let maxY = Math.max(data.coordinate[i].y1, data.coordinate[i].y2)
                if (x >= minX && x <= maxX && y >= minY && y <= maxY) {
                    return i
                }
            }
        }
        return null
    }
    // 鼠标是否落在删除文本区域
    #isPointInText = (pos) => {
        let {remove_coordinate } = this.layers[this.drag_index]
        let minX = Math.min(remove_coordinate.x1, remove_coordinate.x1 + 28)
        let maxX = Math.max(remove_coordinate.x1, remove_coordinate.x1 + 28)
        let minY = Math.min(remove_coordinate.y1, remove_coordinate.y1 - 14)
        let maxY = Math.max(remove_coordinate.y1, remove_coordinate.y1 - 14)
        if (pos.x >= minX && pos.x <= maxX && pos.y >= minY && pos.y <= maxY) return true
        else return false
    }
    // 计算旋转图片中心坐标
    #getRotateCoordinate = (x1, y1, x2, y2) => {
        let minX = Math.min(x1, x2)
        let maxX = Math.max(x1, x2)
        let minY = Math.min(y1, y2)
        let maxY = Math.max(y1, y2)

        return {
            x: minX + (maxX - minX) / 2,
            y: minY
        }
    }
    // 计算中心原点坐标
    #getRectCenterPoint = (x1, y1, x2, y2) => {
        let minX = Math.min(x1, x2)
        let maxX = Math.max(x1, x2)
        let minY = Math.min(y1, y2)
        let maxY = Math.max(y1, y2)

        return {
            x: minX + (maxX - minX) / 2,
            y: minY + (maxY - minY) / 2
        }
    }
    // 计算删除按钮的位置
    #getRemoveCoordinate = (x2, y1) => {
        return {
            x1: x2 - 30,
            y1: y1 + 15,
        }
    }
    // 计算旋转后旋转图片的坐标
    calculateRotatedImgCoordinates = () => {
        let {x1, y1, x2, y2, rotate_after_coordinate, rotate_coordinate, rotate} = this.layers[this.drag_index]
        // 旋转中心坐标
        let centerX = x1 + (x2 - x1) / 2
        let centerY = y1 + (y2 - y1) / 2

        let cos = Math.cos(rotate * Math.PI / 180)
		let sin = Math.sin(rotate * Math.PI / 180)

        // 某个点旋转前坐标
		let rotateX = rotate_coordinate.x - this.rotate_img.width / 2 + 20
		let rotateY = (rotate_coordinate.y - this.rotate_img.height / 2 + 10)
    
        let rotateAbsX = (rotateX - centerX)
		let rotateAbsY = -(rotateY - centerY)

        // 新坐标
		let newX = centerX + rotateAbsX * cos - rotateAbsY * sin
		let newY = centerY + rotateAbsX * sin + rotateAbsY * cos
    
        return {
            x: newX - this.rotate_img.width /2,
            y: newY - this.rotate_img.height /2
        }
    }
    // 计算旋转后四个顶点坐标
    calculateRotatedRectCoordinates = () => {
        if (this.drag_index != 0 || this.drag_index < 0) return []
        let {x1, y1, x2, y2, rotate} = this.layers[this.drag_index]
        let centerX = x1 + (x2 - x1) / 2
        let centerY = y1 + (y2 - y1) / 2
        let cos = Math.cos(rotate * Math.PI / 180)
		let sin = Math.sin(rotate * Math.PI / 180)

        // 计算旋转后的矩形四个顶点相对于矩形中心的坐标
        let topLeftX = -(x2 - x1) / 2
        let topLeftY = -(y2 - y1) / 2
        let topRightX = (x2 - x1) / 2
        let topRightY = -(y2 - y1) / 2
        let bottomLeftX = -(x2 - x1) / 2
        let bottomLeftY = (y2 - y1) / 2
        let bottomRightX = (x2 - x1) / 2
        let bottomRightY = (y2 - y1) / 2

        // 应用旋转变换得到旋转后的矩形的四个顶点坐标
        let rotatedTopLeftX = topLeftX * cos - topLeftY * sin
        let rotatedTopLeftY = topLeftX * sin + topLeftY * cos
        let rotatedTopRightX = topRightX * cos - topRightY * sin
        let rotatedTopRightY = topRightX * sin + topRightY * cos
        let rotatedBottomLeftX = bottomLeftX * cos - bottomLeftY * sin
        let rotatedBottomLeftY = bottomLeftX * sin + bottomLeftY * cos
        let rotatedBottomRightX = bottomRightX * cos - bottomRightY * sin
        let rotatedBottomRightY = bottomRightX * sin + bottomRightY * cos
    
        // 计算旋转后的矩形四个顶点的绝对坐标
	    let rotatedTopLeftAbsoluteX = centerX + rotatedTopLeftX;
	    let rotatedTopLeftAbsoluteY = centerY + rotatedTopLeftY;
	    let rotatedTopRightAbsoluteX = centerX + rotatedTopRightX;
	    let rotatedTopRightAbsoluteY = centerY + rotatedTopRightY;
	    let rotatedBottomLeftAbsoluteX = centerX + rotatedBottomLeftX;
	    let rotatedBottomLeftAbsoluteY = centerY + rotatedBottomLeftY;
	    let rotatedBottomRightAbsoluteX = centerX + rotatedBottomRightX;
	    let rotatedBottomRightAbsoluteY = centerY + rotatedBottomRightY;
    
        return [
            { x: rotatedTopLeftAbsoluteX, y: rotatedTopLeftAbsoluteY },
            { x: rotatedTopRightAbsoluteX, y: rotatedTopRightAbsoluteY },
            { x: rotatedBottomLeftAbsoluteX, y: rotatedBottomLeftAbsoluteY },
            { x: rotatedBottomRightAbsoluteX, y: rotatedBottomRightAbsoluteY }
        ]
    }
    // 设置数据
    setData = (data, color) => {
        this.layers = []
        let proportion_width = this.canvas.width / 100
        let proportion_height = this.canvas.height / 100
        console.log(data, color)
        let default_color = [color[0]]
        data.forEach((item, index) => {
            if (item.result != null && item.result.length > 0) {
                item.result.forEach((t, i) => {
                    let x1 = t.value.x * proportion_width
                    let y1 = t.value.y * proportion_height
                    let x2 = x1 + t.value.width * proportion_width
                    let y2 = y1 + t.value.height * proportion_height

                    let cur_color;

                    let temp = {}
                    temp.x1 = x1
                    temp.y1 = y1
                    temp.x2 = x2
                    temp.y2 = y2
                    temp.id = t.id

                    // 处理标签被删除
                    if (t.value?.rectanglelabels == null || t.value?.rectanglelabels[0] == null) {
                        cur_color = default_color
                    } else {
                        cur_color = color.filter((item) => item.value === t.value.rectanglelabels[0])
                        if (cur_color.length === 0) {
                            cur_color = default_color
                        }
                        temp.label_name = t.value.rectanglelabels[0]
                    }
                    // console.log(cur_color, 'background_opacity找不到')
                    temp.color = cur_color[0].background_opacity.replace('.2', '.5')

                    // temp.label_name = t.value.rectanglelabels[0]

                    temp.center_point = this.#getRectCenterPoint(x1, y1, x2, y2) // 图形中心坐标
                    // 伸缩
                    temp.coordinate = this.#getCoordinate(x1, y1, x2, y2)
                    // 旋转
                    temp.rotate = t.value.rotation
                    temp.rotate_coordinate = this.#getRotateCoordinate(x1, y1, x2, y2)
                    temp.rotate_after_coordinate = null
                    temp.remove_coordinate = this.#getRemoveCoordinate(x2, y1)
                    // 创建id
                    temp.create_id = item.id

                    this.layers.push(temp)
                    this.id++
                })
            }

        })
        setTimeout(() => {
            this.drawAll()
        }, 100)
    }
    // 计算拉伸后图形的坐标
    calculateScaleCoordinates = (x1, y1, x2, y2) => {
        let newX1,newY1,newX2,newY2;
        if (x1 < x2 && y1 < y2) {
            newX1 = x1
            newX2 = x2
            newY1 = y1
            newY2 = y2
        } else if (x1 < x2 && y1 > y2) {
            newX1 = x1
            newX2 = x2
            newY1 = y2
            newY2 = y1
        } else if (x1 > x2 && y1 > y2) {
            newX1 = x2
            newX2 = x1
            newY1 = y2
            newY2 = y1
        } else if (x1 > x2 && y1 < y2) {
            newX1 = x2
            newX2 = x1
            newY1 = y1
            newY2 = y2
        }

        return {
            newX1,
            newY1,
            newX2,
            newY2
        }
    }

    onmousedown = (e) => {
        let pos = this.#getPosition(e)

        // 伸缩
        if (this.is_scale && this.auxiliary_line) {
            let index = this.#isInCornerPath(pos.x, pos.y, this.layers[this.drag_index])
            if (index != null) {
                this.operation = 2
                this.scale_index = index
                this.drag_position = {
                    x: pos.x,
                    y: pos.y
                }
                return
            }
        }

        // 旋转
        if (this.is_rotate && this.auxiliary_line) {
            if (
                this.layers[this.drag_index].rotate != null &&
                this.layers[this.drag_index].rotate_after_coordinate != null  
            ) {
                let minX = this.layers[this.drag_index].rotate_img_coordinate.x
                let maxX = this.layers[this.drag_index].rotate_img_coordinate.x + this.rotate_img.width
                
                let minY = this.layers[this.drag_index].rotate_img_coordinate.y
                let maxY = this.layers[this.drag_index].rotate_img_coordinate.y + this.rotate_img.height
            
                if (pos.x >= minX && pos.x <= maxX && pos.y >= minY && pos.y <= maxY) {
                    this.operation = 3
                    return
                }
            } else {
                let obj = {
                    x1: this.layers[this.drag_index].rotate_coordinate.x - this.rotate_img.width / 2,
                    y1: this.layers[this.drag_index].rotate_coordinate.y - this.rotate_img.height / 2 - 12,
                    x2: this.layers[this.drag_index].rotate_coordinate.x - this.rotate_img.width / 2 + this.rotate_img.width,
                    y2: this.layers[this.drag_index].rotate_coordinate.y - this.rotate_img.height / 2 - 12 + this.rotate_img.height
                }

                let minX = Math.min(obj.x1, obj.x2)
                let maxX = Math.max(obj.x1, obj.x2)
                let minY = Math.min(obj.y1, obj.y2)
                let maxY = Math.max(obj.y1, obj.y2)
                if (pos.x >= minX && pos.x <= maxX && pos.y >= minY && pos.y <= maxY) {
                    this.operation = 3
                    return
                }
            }
        }

        let is_point = this.#isPointInRect(pos.x, pos.y)
        if (is_point) { // 拖拽
            this.flag = true
            this.operation = 1
            this.drag_index = is_point.i
            this.drag_position = {
                x: pos.x,
                y: pos.y
            }
        } else { // 绘制
            if (this.must && this[this.must]) {
                // this.flag = true
                this.operation = 0
                this.position.x1 = pos.x
                this.position.y1 = pos.y
            } else {
                return null
            }
        }
    }
    onmousemove = (e) => {
        let pos = this.#getPosition(e)

        // 绘制
        if (this.operation === 0) {
            this.position.x2 = pos.x
            this.position.y2 = pos.y
            this.drawRect()
        }

        // 拖拽
        if (this.operation === 1) {
            // 计算开始拖拽的坐标，到鼠标移动后的位置的偏移量
            let offset = {
                x: pos.x - this.drag_position.x,
                y: pos.y - this.drag_position.y
            }

            let {x1, y1, x2, y2, id, color, rotate, label_name, create_id} = this.layers[this.drag_index]
            // 重新计算当前拖拽坐标
            this.layers[this.drag_index] = {
                x1: x1 + offset.x,
                y1: y1 + offset.y,
                x2: x2 + offset.x,
                y2: y2 + offset.y,
                coordinate: this.#getCoordinate(
                    this.layers[this.drag_index].x1,
                    this.layers[this.drag_index].y1,
                    this.layers[this.drag_index].x2,
                    this.layers[this.drag_index].y2
                ),
                rotate_coordinate: this.#getRotateCoordinate(
                    this.layers[this.drag_index].x1,
                    this.layers[this.drag_index].y1,
                    this.layers[this.drag_index].x2,
                    this.layers[this.drag_index].y2
                ),
                center_point: this.#getRectCenterPoint(
                    this.layers[this.drag_index].x1,
                    this.layers[this.drag_index].y1,
                    this.layers[this.drag_index].x2,
                    this.layers[this.drag_index].y2
                ),
                remove_coordinate: this.#getRemoveCoordinate(
                    this.layers[this.drag_index].x2,
                    this.layers[this.drag_index].y1
                ),
                id,
                color,
                rotate,
                label_name,
                create_id
            }
            // 保存拖拽坐标
            this.drag_position = {
                x: pos.x,
                y: pos.y
            }

            this.flag = false
            this.drawAll()
        }
    
        // 伸缩
        if (this.operation === 2) {
            // this.position.x1 = this.layers[this.drag_index].x1
            // this.position.y1 = this.layers[this.drag_index].y1

            // 计算开始拖拽的坐标，到鼠标移动后的位置的偏移量
            let offset = {
                x: pos.x - this.drag_position.x,
                y: pos.y - this.drag_position.y
            }
            let {x1, y1, x2, y2} = this.layers[this.drag_index]
            // 重新计算x1, y1, x2, y2
            if (this.scale_index === 0) {
                this.layers[this.drag_index].x1 = x1 + offset.x
                this.layers[this.drag_index].y1 = y1 + offset.y
            } else if (this.scale_index === 3) {
                this.layers[this.drag_index].x2 = x2 + offset.x
                this.layers[this.drag_index].y2 = y2 + offset.y
            } else if (this.scale_index === 1) {
                if (this.scale_position.x1 === null || this.scale_position.y1 === null) {
                    this.scale_position.x1 = x1
                    this.scale_position.y1 = y2
                    this.layers[this.drag_index].y2 = y1 + offset.y
                    this.reverse = true
                } else {
                    this.layers[this.drag_index].y2 = y2 + offset.y
                }
                this.layers[this.drag_index].x2 = x2 + offset.x
                this.layers[this.drag_index].x1 = this.scale_position.x1
                this.layers[this.drag_index].y1 = this.scale_position.y1
            } else if (this.scale_index === 2) {
                if (this.scale_position.x1 === null || this.scale_position.y1 === null) {
                    this.scale_position.x1 = x2
                    this.scale_position.y1 = y1
                    this.layers[this.drag_index].x2 = x1 + offset.x
                    this.reverse = true
                } else {
                    this.layers[this.drag_index].x2 = x2 + offset.x
                }
                this.layers[this.drag_index].y2 = y2 + offset.y
                this.layers[this.drag_index].x1 = this.scale_position.x1
                this.layers[this.drag_index].y1 = this.scale_position.y1
            }
            else if (this.scale_index === '3') {
                this.layers[this.drag_index].x1 = x1 + offset.x
                this.layers[this.drag_index].y1 = y1 + offset.y
            } else if (this.scale_index === '0') {
                this.layers[this.drag_index].x2 = x2 + offset.x
                this.layers[this.drag_index].y2 = y2 + offset.y
            } else if (this.scale_index === '1') {
                if (this.scale_position.x1 === null || this.scale_position.y1 === null) {
                    this.scale_position.x1 = x2
                    this.scale_position.y1 = y1
                    this.layers[this.drag_index].x2 = x1 + offset.x
                    this.reverse = true
                } else {
                    this.layers[this.drag_index].x2 = x2 + offset.x
                }
                this.layers[this.drag_index].y2 = y2 + offset.y
                this.layers[this.drag_index].x1 = this.scale_position.x1
                this.layers[this.drag_index].y1 =  this.scale_position.y1
            } else if (this.scale_position === '2') {
                if (this.scale_position.x1 === null || this.scale_position.y1 === null) {
                    this.scale_position.x1 = x1
                    this.scale_position.y1 = y2
                    this.layers[this.drag_index].y2 = y1 + offset.y
                    this.reverse = true
                } else {
                    this.layers[this.drag_index].y2 = y2 + offset.y
                }
                this.layers[this.drag_index].x2 = x2 + offset.x
                this.layers[this.drag_index].x1 = this.scale_position.x1
                this.layers[this.drag_index].y1 = this.scale_position.y1
            }
            // let coordinate = this.calculateScaleCoordinates(
            //     this.layers[this.drag_index].x1,
            //     this.layers[this.drag_index].y1,
            //     this.layers[this.drag_index].x2,
            //     this.layers[this.drag_index].y2
            // )
            // this.layers[this.drag_index].x1 = coordinate.newX1
            // this.layers[this.drag_index].y1 = coordinate.newY1
            // this.layers[this.drag_index].x2 = coordinate.newX2
            // this.layers[this.drag_index].y2 = coordinate.newY2

            this.layers[this.drag_index].coordinate = this.#getCoordinate(
                this.layers[this.drag_index].x1,
                this.layers[this.drag_index].y1,
                this.layers[this.drag_index].x2,
                this.layers[this.drag_index].y2
            )
            this.layers[this.drag_index].rotate_coordinate = this.#getRotateCoordinate(
                this.layers[this.drag_index].x1,
                this.layers[this.drag_index].y1,
                this.layers[this.drag_index].x2,
                this.layers[this.drag_index].y2
            )
            this.layers[this.drag_index].center_point = this.#getRectCenterPoint(
                this.layers[this.drag_index].x1,
                this.layers[this.drag_index].y1,
                this.layers[this.drag_index].x2,
                this.layers[this.drag_index].y2
            )

            this.drawAll()
            this.drag_position = {
                x: pos.x,
                y: pos.y
            }
            this.setCursor(pos)
        }

        // 旋转
        if (this.operation === 3) {
            let rect = this.canvas.getBoundingClientRect()
            let mouseX = e.clientX - rect.left
            let mouseY = e.clientY - rect.top
            let {x1, y1, x2, y2} = this.layers[this.drag_index]
            let dx = mouseX - (x1 + (x2 - x1) / 2)
            let dy = mouseY - (y1 + (y2 - y1) / 2)
            this.layers[this.drag_index].rotate = Math.atan2(-dx, dy) * 180 / Math.PI
            this.drawAll()
        }

        // 鼠标样式修改
        // if (this.layers.length > 0 && this.auxiliary_line) {
        //     this.setCursor(pos)
        // }
    }
    onmouseup = (e) => {
        // 绘制
        if (this.operation === 0 && this.is_draw) {
            let {x1, y1, x2, y2} = this.position
            // let newX1,newY1,newX2,newY2;
            let coordinate = this.calculateScaleCoordinates(x1, y1, x2, y2)
            // if (x1 < x2 && y1 < y2) {
            //     newX1 = x1
            //     newX2 = x2
            //     newY1 = y1
            //     newY2 = y2
            // } else if (x1 < x2 && y1 > y2) {
            //     newX1 = x1
            //     newX2 = x2
            //     newY1 = y2
            //     newY2 = y1
            // } else if (x1 > x2 && y1 > y2) {
            //     newX1 = x2
            //     newX2 = x1
            //     newY1 = y2
            //     newY2 = y1
            // } else if (x1 > x2 && y1 < y2) {
            //     newX1 = x2
            //     newX2 = x1
            //     newY1 = y1
            //     newY2 = y2
            // }
            let minX = Math.min(x1, x2)
			let maxX = Math.max(x1, x2)
			let minY = Math.min(y1, y2)
			let maxY = Math.max(y1, y2)
            if (maxX - minX > 20 && maxY - minY > 20) {
                let obj = {
                    x1: coordinate.newX1,
                    y1: coordinate.newY1,
                    x2: coordinate.newX2,
                    y2: coordinate.newY2,
                    id: this.id,
                    color: this.color,
                    label_name: this.label_name,
                    center_point: this.#getRectCenterPoint(coordinate.newX1, coordinate.newY1, coordinate.newX2, coordinate.newY2), // 图形中心坐标
                    // 伸缩
                    coordinate: this.is_scale ? this.#getCoordinate(coordinate.newX1, coordinate.newY1, coordinate.newX2, coordinate.newY2) : [],
                    // 旋转
                    rotate: null,
                    rotate_coordinate: this.is_rotate ? this.#getRotateCoordinate(coordinate.newX1, coordinate.newY1, coordinate.newX2, coordinate.newY2) : [],
                    rotate_after_coordinate: null,
                    create_id: ''
                }
                this.undo_list.push(obj)
                this.layers.push(obj)
                this.id++
            }
            this.drawAll()
            this.event = {
                type: 'draw',
                id: ''
            }
            document.dispatchEvent(window.myCustomEvent)
        }

        // 拖拽
        if (this.operation === 1) {
            // 辅助框显隐
            if (this.is_scale && typeof this.drag_index === 'number' && this.flag) {
                if (this.drag_index === this.pre_drag_index) {
                    this.auxiliary_line = false
                    this.pre_drag_index = null
                } else {
                    this.auxiliary_line = true
                    this.pre_drag_index = this.drag_index
                }
                this.drawAll()
            } else {
                this.undo_list.push({...this.layers[this.drag_index]})
                this.event = {
                    type: 'drag',
                    id: this.layers[this.drag_index].create_id
                }
                document.dispatchEvent(window.myCustomEvent)
            }
        }

        // 伸缩
        if (this.operation === 2) {
            let {x1, y1, x2, y2} = this.layers[this.drag_index]
            let coordinate = this.calculateScaleCoordinates(x1, y1, x2, y2)
            // if (this.reverse) {
                this.layers[this.drag_index].x1 = coordinate.newX1
                this.layers[this.drag_index].y1 = coordinate.newY1
                this.layers[this.drag_index].x2 = coordinate.newX2
                this.layers[this.drag_index].y2 = coordinate.newY2
                this.layers[this.drag_index].coordinate = this.#getCoordinate(
                    this.layers[this.drag_index].x1,
                    this.layers[this.drag_index].y1,
                    this.layers[this.drag_index].x2,
                    this.layers[this.drag_index].y2
                )

                // this.layers[this.drag_index].x1 = x1
                // this.layers[this.drag_index].y1 = y2
                // this.layers[this.drag_index].x2 = x2
                // this.layers[this.drag_index].y2 = y1
                // this.layers[this.drag_index].coordinate = this.#getCoordinate(
                //     this.layers[this.drag_index].x1,
                //     this.layers[this.drag_index].y1,
                //     this.layers[this.drag_index].x2,
                //     this.layers[this.drag_index].y2
                // )
            // }
            this.undo_list.push({...this.layers[this.drag_index]})
            this.drawAll()
            this.event = {
                type: 'scale',
                id: this.layers[this.drag_index].create_id
            }
            document.dispatchEvent(window.myCustomEvent)
        }

        // 旋转
        if (this.operation === 3) {
            this.event = {
                type: 'rotate',
                id: this.layers[this.drag_index].create_id
            }
            document.dispatchEvent(window.myCustomEvent)
        }

        // 本次操作结束，还原默认值
        this.resizeDefault()
    }
    onclick = (e) => {
        let pos = this.#getPosition(e)

        // 删除
        if (this.drag_index != null && this.#isPointInText(pos)) {
            const cur_del = this.layers.splice(this.drag_index, 1)
            this.drag_index = null
            this.auxiliary_line = false
            // this.drawAll()

            this.event = {
                type: 'delete',
                id: cur_del[0].create_id
            }
            document.dispatchEvent(window.myCustomEvent)
        }
    }
}

export default Drawer