import bindAll from 'lodash.bindall';
import PropTypes from 'prop-types';
import React from 'react';
import VM from 'scratch-vm';
import {connect} from 'react-redux';

import ControlsComponent from '../components/controls/controls.jsx';
import {setRunningState} from '../reducers/vm-status';

// import xhr from 'xhr';

class Controls extends React.Component {
    constructor (props) {
        super(props);
        this.state = {
            rerunTpu: '',
            isrunstop:'',
        }
        bindAll(this, [
            'handleGreenFlagClick',
            'handleStopAllClick',
            'handleOnReRunClick'
        ]);
    }

    handleGreenFlagClick (e) {
        e.preventDefault();
        if (e.shiftKey) {
            this.props.vm.setTurboMode(!this.props.turbo);
        } else {
            if (!this.props.isStarted) {
                this.props.vm.start();
            }
            this.props.vm.greenFlag();
            // 开启运行状态
            this.props.onProjectRunState(true)
        }
    }
    handleStopAllClick (e) {
        e.preventDefault();
        this.props.vm.stopAll(true);
        // 关闭运行状态
        this.props.onProjectRunState(false)
    }
    handleOnReRunClick(e) {
        
    }
    render () {
        const {
            vm, // eslint-disable-line no-unused-vars
            isStarted, // eslint-disable-line no-unused-vars
            projectRunning,
            turbo,
            onProjectRunState,
            ...props
        } = this.props;
        return (
            <ControlsComponent
                {...props}
                active={projectRunning}
                turbo={turbo}
                onGreenFlagClick={this.handleGreenFlagClick}
                onStopAllClick={this.handleStopAllClick}
                onReRunClick={this.handleOnReRunClick}
            />
        );
    }
}

Controls.propTypes = {
    isStarted: PropTypes.bool.isRequired,
    projectRunning: PropTypes.bool.isRequired,
    turbo: PropTypes.bool.isRequired,
    vm: PropTypes.instanceOf(VM)
};

const mapStateToProps = state => ({
    isStarted: state.scratchGui.vmStatus.running,
    projectRunning: state.scratchGui.vmStatus.running,
    turbo: state.scratchGui.vmStatus.turbo
});
// no-op function to prevent dispatch prop being passed to component
const mapDispatchToProps = (dispatch) => ({
    onProjectRunState: (bol) => dispatch(setRunningState(bol))
});

export default connect(mapStateToProps, mapDispatchToProps)(Controls);
