import React from "react";
import bindAll from 'lodash.bindall';
import styles from './take-photo.css';
import LANG_MESSAGE from './lang.js'
import { Select } from 'antd';
const { Option } = Select;

class TakePhoto extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            device_list: [],
            device_def: '',
            device_val: '',

            status: false,
            photo: '',
        }
        this.mx = 0
        this.my = 0
        this.dx = 0
        this.dy = 0
        this.isDraging = false
        this.fullBlob = null,
        this.currentStream = null,

        bindAll(this, [
            'getCameraList',
            'takePhoto',
            'changePhoto',
            'uploadHandle',
            'uploadImage',
        ])
    }
    componentDidMount() {
        this.getCameraList()

        // 旧版本浏览器可能根本不支持mediaDevices，我们首先设置一个空对象
        if (navigator.mediaDevices === undefined) {
            navigator.mediaDevices = {};
        }

        // 一些浏览器实现了部分mediaDevices，我们不能只分配一个对象
        // 使用getUserMedia，因为它会覆盖现有的属性。
        // 这里，如果缺少getUserMedia属性，就添加它。
        if (navigator.mediaDevices.getUserMedia === undefined) {
            navigator.mediaDevices.getUserMedia = function (constraints) {
                // 首先获取现存的getUserMedia(如果存在)
                let getUserMedia = navigator.webkitGetUserMedia || navigator.mozGetUserMedia;
                // 有些浏览器不支持，会返回错误信息
                // 保持接口一致
                if (!getUserMedia) {
                    return Promise.reject(new Error('getUserMedia is not implemented in this browser'));
                }
                //否则，使用Promise将调用包装到旧的navigator.getUserMedia
                return new Promise(function (resolve, reject) {
                    getUserMedia.call(navigator, constraints, resolve, reject);
                });
            }
        }
        let constraints = {
            audio: false,
            // video: {
            //     width: 480,
            //     height: 360
            // },
            video: true
        };
        navigator.mediaDevices.getUserMedia(constraints).then(stream => {
            let _chunks = [];
            // 视频格式
            let VIDEO_FORMAT = 'video/webm';
            if (!MediaRecorder.isTypeSupported(VIDEO_FORMAT)) {
                console.error('当前浏览器不支持该编码类型')
                return;
            }
            this.currentStream = stream
            this.refs.takePhotoVideo.srcObject = stream
            this.refs.takePhotoVideo.play()
        }).catch((err) => {
            let message = err.message || err
            console.log(message)
        });

        //获取可见窗口大小
        let bodyW = document.documentElement.clientWidth;
        let bodyH = document.documentElement.clientHeight;
        //获取对话框宽、高
        let elW = document.getElementById('take-photo-box').offsetWidth;
        let elH = document.getElementById('take-photo-box').offsetHeight;
        document.getElementById('take-photo-box').style.left = (bodyW - elW) / 2 + 'px';
        document.getElementById('take-photo-box').style.top = (bodyH - elH) / 3 + 'px';

        document.getElementById('take-photo-header').addEventListener('mousedown', (evnet) => {
            let e = evnet || window.event
            this.mx = e.pageX
            this.my = e.pageY
            this.dx = document.getElementById('take-photo-box').offsetLeft
            this.dy = document.getElementById('take-photo-box').offsetTop

            this.isDraging = true
        })

        document.onmousemove = (event1) => {
            let e = event1 || window.event
            let x = e.pageX
            let y = e.pageY
            if (this.isDraging) {
                let moveX = this.dx + x - this.mx
                let moveY = this.dy + y - this.my
                if (moveX < 0) moveX = 0
                if (moveY < 0) moveY = 0
                document.getElementById('take-photo-box').style.left = moveX + 'px';
                document.getElementById('take-photo-box').style.top = moveY + 'px';
            }
        }

        document.getElementById('take-photo-header').addEventListener('mouseup', (e) => {
            this.mx = 0
            this.my = 0
            this.dx = 0
            this.dy = 0
            this.isDraging = false
        })
    }

    getCameraList(e) {
        navigator.mediaDevices.enumerateDevices().then((list) => {
            let device_list = list.filter(res => res.deviceId !== '' && res.kind == 'videoinput')
            let value = device_list.length > 0 ? device_list[0].label : ''
            this.setState({
                device_list,
                device_def: value,
                device_val: value
            })
        })
    }
    takePhoto() {
        let dataUrl
        if (!this.state.status) {
            let canvas = this.refs.takePhotoCanvas
            let ctx = canvas.getContext('2d')
            ctx.drawImage(this.refs.takePhotoVideo, 0, 0, 480, 360)
            dataUrl = canvas.toDataURL()
            this.refs.takePhotoVideo.style.display = 'none'
            this.refs.takePhotoImg.style.display = 'block'
        } else {
            this.refs.takePhotoVideo.style.display = 'block'
            this.refs.takePhotoImg.style.display = 'none'
        }
        this.setState({
            status: !this.state.status,
            photo: dataUrl
        })
    }
    changePhoto(e) {
        let filter = this.state.device_list.filter(item => item.label === e)
        let constraints = {
            audio: false,
            video: {
                width: 480,
                height: 360,
                transform: "scaleX(-1)",
                deviceId: {
                    exact: filter[0].deviceId
                },
            }
        }
        navigator.mediaDevices.getUserMedia(constraints)
            .then((stream) => {
                if (this.currentStream) {
                    this.currentStream.getTracks().forEach((track) => {
                        track.stop()
                    })
                }
                this.currentStream = stream
                this.refs.takePhotoVideo.srcObject = stream
                this.refs.takePhotoVideo.play()
            })
            .error(error => {
                console.error(error)
            })
    }
    uploadHandle() {
        document.getElementById('take-photo-upload').click()
    }
    uploadImage(e) {
        let input = document.getElementById('take-photo-upload')
        let fileData = input.files[0]
        if (!/\.(jpg|png)$/.test(fileData.name.toLowerCase())) {
            // this.props.onChangeMessgae({
            //     visible: true,
            //     content: '格式错误,请上传jpg、png格式的文件',
            //     type: 'fail'
            // })
            return
        }

        let reader = new FileReader()
        reader.onload = (event) => {
            this.setState({
                photo: reader.result,
                status: true
            }, () => {
                input.value = ''
                this.refs.takePhotoVideo.style.display = 'none'
                this.refs.takePhotoImg.style.display = 'block'
            })
        }
        reader.readAsDataURL(fileData)
    }

    render() {
        return (
            <div id="take-photo-box" className={styles.container}>
                <div id="take-photo-header" className={styles.header}>
                    <div className={styles.title}>{this.props.intl.formatMessage(LANG_MESSAGE.camera)}</div>
                    <div className={styles.select}>
                        {this.state.device_list.length > 0 ? (
                            <Select 
                                defaultValue={this.state.device_def}
                                style={{ width: 180 }}
                                onChange={this.changePhoto}
                            >
                                {this.state.device_list.map((item, index) => {
                                    return (
                                        <Option key={index} value={item.label}>{item.label}</Option>
                                    )
                                })}
                            </Select>
                        ) : null}
                    </div>
                    <div className={styles.close} onClick={() => this.props.changeTakePhoto(false)}>
                        <div>
                            <img src="data:image/png;base64," alt="" />
                        </div>
                    </div>
                </div>
                <div className={styles.content}>
                    <div>
                        <video ref="takePhotoVideo"></video>
                        <canvas ref="takePhotoCanvas" width="480" height="360" ></canvas>
                        <img src={this.state.photo} ref="takePhotoImg"  width="480" height="360" />
                    </div>
                </div>
                <div className={styles.footer}>
                    <button onClick={this.takePhoto} className={styles.takePhoto}>{this.state.status ? this.props.intl.formatMessage(LANG_MESSAGE.retake) : this.props.intl.formatMessage(LANG_MESSAGE.photograph)}</button>
                    <button onClick={this.uploadHandle} className={styles.upload}>{this.props.intl.formatMessage(LANG_MESSAGE.upload)}</button>
                    <input 
                        id="take-photo-upload"
                        className={styles.takePhotoUpload}
                        type="file"
                        accept=".jpg,.png"
                        onChange={this.uploadImage}
                    />
                    <button onClick={this.props.takePhotoConfirm} className={styles.confirm}>{this.props.intl.formatMessage(LANG_MESSAGE.ok)}</button>
                </div>
            </div>
        )
    }
}

export default TakePhoto
