import bindAll from 'lodash.bindall';
import React from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {intlShape, injectIntl, defineMessages} from 'react-intl';

import {openSpriteLibrary, closeSpriteLibrary} from '../reducers/modals';
import {activateTab, COSTUMES_TAB_INDEX, BLOCKS_TAB_INDEX} from '../reducers/editor-tab';
import {setReceivedBlocks} from '../reducers/hovered-target';
import {showStandardAlert, closeAlertWithId} from '../reducers/alerts';
import {setRestore} from '../reducers/restore-deletion';
import DragConstants from '../lib/drag-constants';
import TargetPaneComponent from '../components/target-pane/target-pane.jsx';
import {BLOCKS_DEFAULT_SCALE} from '../lib/layout-constants';
import spriteLibraryContent from '../lib/libraries/sprites.json';
import {handleFileUpload, spriteUpload} from '../lib/file-uploader.js';
import sharedMessages from '../lib/shared-messages';
import {emptySprite} from '../lib/empty-assets';
import {highlightTarget} from '../reducers/targets';
import {fetchSprite, fetchCode} from '../lib/backpack-api';
import randomizeSpritePosition from '../lib/randomize-sprite-position';
import downloadBlob from '../lib/download-blob';

import { changeRole, changeSourceMaterial, setComDialog, setDialogConfirm, addRole } from '../reducers/status'
import cloneDeep from 'lodash.clonedeep';
// 无用引入
// import ScratchBlocks from 'scratch-blocks'

const messages = defineMessages({
    deleteRoleHead: {
        id: 'gui.targetPane.deleteRoleHead',
        description: '删除角色“{name}”吗',
        defaultMessage: '删除角色“{name}”吗'
    },
    deleteRoleContent: {
        id: 'gui.targetPane.deleteRoleContent',
        description: '该角色中的造型，积木也会被同时删除',
        defaultMessage: '该角色中的造型，积木也会被同时删除'
    }
})

let is_delete = false

class TargetPane extends React.Component {
    constructor (props) {
        super(props);
        bindAll(this, [
            'handleActivateBlocksTab',
            'handleBlockDragEnd',
            'handleChangeSpriteRotationStyle',
            'handleChangeSpriteDirection',
            'handleChangeSpriteName',
            'handleChangeSpriteSize',
            'handleChangeSpriteVisibility',
            'handleChangeSpriteX',
            'handleChangeSpriteY',
            'handleChangeSpriteW',
            'handleChangeSpriteH',
            'handleChangeSpriteIn',
            'handleChangeSpriteOut',
            'handleDeleteSprite',
            'handleDrop',
            'handleDuplicateSprite',
            'handleExportSprite',
            'handleNewSprite',
            'handleSelectSprite',
            'handleSurpriseSpriteClick',
            'handlePaintSpriteClick',
            'handleFileUploadClick',
            'handleSpriteUpload',
            'setFileInput',
            'handleOpenClick',
            'changeTargeID',
        ]);
        this.click_arr = []
        this.click_type = {
            tag: '',
            id: ''
        }
        this.state = {
            dialog_confirm: {
                bol: false,
                type: null,
                id: null
            }
        }
    }
    componentDidMount () {
        this.setState({
            dialog_confirm: this.props.dialogconfirm
        })
        this.props.vm.addListener('BLOCK_DRAG_END', this.handleBlockDragEnd);
    }
    componentWillUnmount () {
        this.props.vm.removeListener('BLOCK_DRAG_END', this.handleBlockDragEnd);
    }
    componentDidUpdate (prevProps, prevState) {
        if (
            (prevState.dialog_confirm.bol !== this.props.dialogconfirm.bol) && 
            (this.props.dialogconfirm.type === 'all-role')
        ) {
            if (!is_delete) {
                this.props.onSetComDialog({
                    show: false,
                    header: null,
                    content: null,
                    type: null,
                    id: null
                })
                this.props.onSetDialogConfirm({
                    bol: false,
                    type: '',
                    id: null
                })
                is_delete = true

                const restoreSprite = this.props.vm.deleteSprite(this.props.dialogconfirm.id);
                const restoreFun = () => restoreSprite().then(this.handleActivateBlocksTab);

                this.props.dispatchUpdateRestore({
                    restoreFun: restoreFun,
                    deletedItem: 'Sprite'
                });
            } else {
                is_delete = false
            }
        }
    }
    handleOpenClick () {
        this.props.onChagneStatus(true)
    }
    handleChangeSpriteDirection (direction) {
        this.props.vm.postSpriteInfo({direction});
    }
    handleChangeSpriteRotationStyle (rotationStyle) {
        this.props.vm.postSpriteInfo({rotationStyle});
    }
    handleChangeSpriteName (name) {
        this.props.vm.renameSprite(this.props.editingTarget, name);
    }
    handleChangeSpriteSize (size) {
        this.props.vm.postSpriteInfo({size});
    }
    handleChangeSpriteVisibility (visible) {
        this.props.vm.postSpriteInfo({visible});
    }
    handleChangeSpriteX (x) {
        this.props.vm.postSpriteInfo({x});
    }
    handleChangeSpriteY (y) {
        this.props.vm.postSpriteInfo({y});
    }
    handleChangeSpriteW (w) {

    }
    handleChangeSpriteH (h) {

    }
    handleChangeSpriteIn (i) {

    }
    handleChangeSpriteOut (o) {

    }
    handleDeleteSprite (id) {
        let data = this.props.vm.extensionManager.runtime.executableTargets.filter((item) => item.id === id )
        this.props.onSetComDialog({
            show: true,
            header: this.props.intl.formatMessage(messages.deleteRoleHead, {name: data[0].sprite.name}),
            content: this.props.intl.formatMessage(messages.deleteRoleContent),
            type: 'all-role',
            id: id
        })
    }
    handleDuplicateSprite (id) {
        this.props.vm.duplicateSprite(id);
    }
    handleExportSprite (id) {
        const spriteName = this.props.vm.runtime.getTargetById(id).getName();
        const saveLink = document.createElement('a');
        document.body.appendChild(saveLink);

        this.props.vm.exportSprite(id).then(content => {
            downloadBlob(`${spriteName}.sprite3`, content);
        });
    }
    handleSelectSprite (id, tagName) {
        this.props.vm.setEditingTarget(id);
        if (this.props.stage && id !== this.props.stage.id) {
            this.props.onHighlightTarget(id);
        }

        if (this.click_type.tag === 'IMG' && this.click_type.id != '' && this.click_type.id != id) {
            this.click_type = {
                tag: tagName,
                id: id
            }
            return
        }

        this.click_type = {
            tag: tagName,
            id: id
        }

        if (tagName === 'IMG') {
            this.changeTargeID()
        } else {
            this.click_arr.push({
                id: id,
                time: new Date().getTime()
            })
            if (this.click_arr.length === 2) {
                let item = this.click_arr[0]
                let item1 = this.click_arr[1]
                if (item.id === item1.id && (item1.time - item.time) < 500) {
                    this.changeTargeID()
                    this.click_arr = []
                } else {
                    this.click_arr.shift(0)
                }
            }
        }

        // let toolbox = ScratchBlocks.mainWorkspace.toolbox_;
        // toolbox.flyout_.hide();
    }
    changeTargeID() {
        if (document.getElementById('targe_id')){
            if (document.getElementById('targe_id').style.zIndex == 100) {
                document.getElementById('targe_id').style.zIndex = -1;
                document.getElementById('targe_id').style.left = '-127px';

                this.click_type = {
                    tag: '',
                    id: ' '
                }
                // ScratchBlocks.Toolbox.prototype.closeTriggerSK()
            } else {
                document.getElementById('targe_id').style.zIndex = 100;
                document.getElementById('targe_id').style.left = '127px';
                // document.getElementsByClassName("blocklyToolboxTriggerIcon")[0].style.right = '4px';
                // document.getElementsByClassName("blocklyToolboxTriggerIcon")[0].setAttribute('src', ScratchBlocks.mainWorkspace.options.pathToMedia + 'show.svg');
            }
        }
    }
    handleSurpriseSpriteClick () {
        const surpriseSprites = spriteLibraryContent.filter(sprite =>
            (sprite.tags.indexOf('letters') === -1) && (sprite.tags.indexOf('numbers') === -1)
        );
        const item = surpriseSprites[Math.floor(Math.random() * surpriseSprites.length)];
        randomizeSpritePosition(item);
        this.props.vm.addSprite(JSON.stringify(item))
            .then(this.handleActivateBlocksTab);
    }
    handlePaintSpriteClick () {
        const formatMessage = this.props.intl.formatMessage;
        const emptyItem = emptySprite(
            formatMessage(sharedMessages.sprite, {index: 1}),
            formatMessage(sharedMessages.pop),
            formatMessage(sharedMessages.costume, {index: 1})
        );
        let old_id = cloneDeep(this.props.vm.editingTarget.id)

        // this.props.vm.addSprite(JSON.stringify(emptyItem));
        this.props.vm.addSprite(JSON.stringify(emptyItem)).then(() => {
            // setTimeout(() => { // Wait for targets update to propagate before tab switching
            //     this.props.onActivateTab(COSTUMES_TAB_INDEX);
            // });
            
            // 记录当前系列绘制目标信息
            this.props.onAddRole({
                is_bol: true,
                type: 'all-role',
                id: this.props.vm.editingTarget.id,
                old_id: old_id
            })
        });
        this.props.onActivateTab(COSTUMES_TAB_INDEX)
        this.props.onChagneStatus(false)
    }
    handleActivateBlocksTab () {
        this.props.onActivateTab(BLOCKS_TAB_INDEX);
    }
    handleNewSprite (spriteJSONString) {
        return this.props.vm.addSprite(spriteJSONString)
            .then(this.handleActivateBlocksTab);
    }
    handleFileUploadClick () {
        // this.props.onChagneStatus(false)
        this.fileInput.click();
    }
    handleSpriteUpload (e) {
        const storage = this.props.vm.runtime.storage;
        this.props.onShowImporting();
        handleFileUpload(e.target, (buffer, fileType, fileName, fileIndex, fileCount) => {
            spriteUpload(buffer, fileType, fileName, storage, newSprite => {
                this.handleNewSprite(newSprite)
                    .then(() => {
                        if (fileIndex === fileCount - 1) {
                            this.props.onCloseImporting();
                        }
                    })
                    .catch(this.props.onCloseImporting);
            }, this.props.onCloseImporting);
        }, this.props.onCloseImporting);
    }
    setFileInput (input) {
        this.fileInput = input;
    }
    handleBlockDragEnd (blocks) {
        // 处理拖拽复制功能，只开放给targetPanetype=2
        if (this.props.targetPanetype === 2 && this.props.hoveredTarget.sprite && this.props.hoveredTarget.sprite !== this.props.editingTarget) {
            this.shareBlocks(blocks, this.props.hoveredTarget.sprite, this.props.editingTarget);
            this.props.onReceivedBlocks(true);
        }
    }
    shareBlocks (blocks, targetId, optFromTargetId) {
        // Position the top-level block based on the scroll position.
        const topBlock = blocks.find(block => block.topLevel);
        if (topBlock) {
            let metrics;
            if (this.props.workspaceMetrics.targets[targetId]) {
                metrics = this.props.workspaceMetrics.targets[targetId];
            } else {
                metrics = {
                    scrollX: 0,
                    scrollY: 0,
                    scale: BLOCKS_DEFAULT_SCALE
                };
            }

            // Determine position of the top-level block based on the target's workspace metrics.
            const {scrollX, scrollY, scale} = metrics;
            const posY = -scrollY + 30;
            let posX;
            if (this.props.isRtl) {
                posX = scrollX + 30;
            } else {
                posX = -scrollX + 30;
            }

            // Actually apply the position!
            topBlock.x = posX / scale;
            topBlock.y = posY / scale;
        }

        return this.props.vm.shareBlocksToTarget(blocks, targetId, optFromTargetId);
    }
    handleDrop (dragInfo) {
        const {sprite: targetId} = this.props.hoveredTarget;
        if (dragInfo.dragType === DragConstants.SPRITE) {
            // Add one to both new and target index because we are not counting/moving the stage
            this.props.vm.reorderTarget(dragInfo.index + 1, dragInfo.newIndex + 1);
        } else if (dragInfo.dragType === DragConstants.BACKPACK_SPRITE) {
            // TODO storage does not have a way of loading zips right now, and may never need it.
            // So for now just grab the zip manually.
            fetchSprite(dragInfo.payload.bodyUrl)
                .then(sprite3Zip => this.props.vm.addSprite(sprite3Zip));
        } else if (targetId) {
            // Something is being dragged over one of the sprite tiles or the backdrop.
            // Dropping assets like sounds and costumes duplicate the asset on the
            // hovered target. Shared costumes also become the current costume on that target.
            // However, dropping does not switch the editing target or activate that editor tab.
            // This is based on 2.0 behavior, but seems like it keeps confusing switching to a minimum.
            // it allows the user to share multiple things without switching back and forth.
            if (dragInfo.dragType === DragConstants.COSTUME) {
                this.props.vm.shareCostumeToTarget(dragInfo.index, targetId);
            } else if (targetId && dragInfo.dragType === DragConstants.SOUND) {
                this.props.vm.shareSoundToTarget(dragInfo.index, targetId);
            } else if (dragInfo.dragType === DragConstants.BACKPACK_COSTUME) {
                // In scratch 2, this only creates a new sprite from the costume.
                // We may be able to handle both kinds of drops, depending on where
                // the drop happens. For now, just add the costume.
                this.props.vm.addCostume(dragInfo.payload.body, {
                    name: dragInfo.payload.name
                }, targetId);
            } else if (dragInfo.dragType === DragConstants.BACKPACK_SOUND) {
                this.props.vm.addSound({
                    md5: dragInfo.payload.body,
                    name: dragInfo.payload.name
                }, targetId);
            } else if (dragInfo.dragType === DragConstants.BACKPACK_CODE) {
                fetchCode(dragInfo.payload.bodyUrl)
                    .then(blocks => this.shareBlocks(blocks, targetId))
                    .then(() => this.props.vm.refreshWorkspace());
            }
        }
    }
    render () {
        /* eslint-disable no-unused-vars */
        const {
            dispatchUpdateRestore,
            isRtl,
            onActivateTab,
            onCloseImporting,
            onHighlightTarget,
            onReceivedBlocks,
            onShowImporting,
            workspaceMetrics,
            rightTab,
            selectedIndex,
            onChagneStatus,
            onSetComDialog,
            onSetDialogConfirm,
            onAddRole,
            ...componentProps
        } = this.props;
        /* eslint-enable no-unused-vars */
        return (
            <TargetPaneComponent
                {...componentProps}
                fileInputRef={this.setFileInput}
                onActivateBlocksTab={this.handleActivateBlocksTab}
                onChangeSpriteDirection={this.handleChangeSpriteDirection}
                onChangeSpriteName={this.handleChangeSpriteName}
                onChangeSpriteRotationStyle={this.handleChangeSpriteRotationStyle}
                onChangeSpriteSize={this.handleChangeSpriteSize}
                onChangeSpriteVisibility={this.handleChangeSpriteVisibility}
                onChangeSpriteX={this.handleChangeSpriteX}
                onChangeSpriteY={this.handleChangeSpriteY}
                onChangeSpriteW={this.handleChangeSpriteW}
                onChangeSpriteH={this.handleChangeSpriteH}
                onChangeSpriteIn={this.handleChangeSpriteIn}
                onChangeSpriteOut={this.handleChangeSpriteOut}
                onDeleteSprite={this.handleDeleteSprite}
                onDrop={this.handleDrop}
                onDuplicateSprite={this.handleDuplicateSprite}
                onExportSprite={this.handleExportSprite}
                onFileUploadClick={this.handleFileUploadClick}
                onPaintSpriteClick={this.handlePaintSpriteClick}
                onSelectSprite={this.handleSelectSprite}
                onSpriteUpload={this.handleSpriteUpload}
                onSurpriseSpriteClick={this.handleSurpriseSpriteClick}
                onOpenClick={this.handleOpenClick}
                rightTab={this.rightTab}
                selectedIndex={selectedIndex}
                onActivateTab={() => this.props.onActivateTab()}
                onActivateCostumesTab={() => this.props.onActivateTab(COSTUMES_TAB_INDEX)}
            />
        );
    }
}

const {
    onSelectSprite, // eslint-disable-line no-unused-vars
    onActivateBlocksTab, // eslint-disable-line no-unused-vars
    ...targetPaneProps
} = TargetPaneComponent.propTypes;

TargetPane.propTypes = {
    intl: intlShape.isRequired,
    onCloseImporting: PropTypes.func,
    onShowImporting: PropTypes.func,
    ...targetPaneProps
};

const mapStateToProps = state => ({
    editingTarget: state.scratchGui.targets.editingTarget,
    hoveredTarget: state.scratchGui.hoveredTarget,
    isRtl: state.locales.isRtl,
    spriteLibraryVisible: state.scratchGui.modals.spriteLibrary,
    sprites: state.scratchGui.targets.sprites,
    stage: state.scratchGui.targets.stage,
    raiseSprites: state.scratchGui.blockDrag,
    workspaceMetrics: state.scratchGui.workspaceMetrics,
});

const mapDispatchToProps = dispatch => ({
    onNewSpriteClick: e => {
        e.preventDefault();
        dispatch(changeRole(false));
        // dispatch(openSpriteLibrary()); // 原始打开素材库
        dispatch(changeSourceMaterial({
            status: true,
            type: 0
        }))
    },
    onRequestCloseSpriteLibrary: () => {
        dispatch(closeSpriteLibrary());
    },
    onActivateTab: tabIndex => {
        dispatch(activateTab(tabIndex));
    },
    onReceivedBlocks: receivedBlocks => {
        dispatch(setReceivedBlocks(receivedBlocks));
    },
    dispatchUpdateRestore: restoreState => {
        dispatch(setRestore(restoreState));
    },
    onHighlightTarget: id => {
        dispatch(highlightTarget(id));
    },
    onCloseImporting: () => dispatch(closeAlertWithId('importingAsset')),
    onShowImporting: () => dispatch(showStandardAlert('importingAsset')),
    onChagneStatus: (state) => dispatch(changeRole(state)),
    onSetComDialog: (params) => dispatch(setComDialog(params)),
    onSetDialogConfirm: (params) => dispatch(setDialogConfirm(params)),
    onAddRole: (params) => dispatch(addRole(params)),
});

export default injectIntl(connect(
    mapStateToProps,
    mapDispatchToProps
)(TargetPane));
